+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return Boolean((value as Aspect | undefined)?.[$aspect]);
+}
+
+export function createAspect<const T extends readonly AspectInput[]>(...inputs: T): Aspect<T> {
+    if (inputs.length < 2) throw new Error('Koota: An aspect requires at least two traits.');
+
+    const traits: Trait[] = [];
+    for (const input of inputs) {
+        if (isAspect(input)) traits.push(...input.traits);
+        else traits.push(input);
+    }
+
+    const fields = new Set<string>();
+    for (const trait of traits) {
+        if (isRelation(trait[$internal].relation)) {
+            throw new Error('Koota: Relations cannot be aspect constituents.');
+        }
+        for (const field of Object.keys(trait.schema)) {
+            if (fields.has(field)) throw new Error(`Koota: Aspect field '${field}' is declared more than once.`);
+            fields.add(field);
+        }
+    }
+
+    const schema = Object.assign({}, ...traits.map((trait) => trait.schema));
+    return Object.freeze({ [$aspect]: true as const, id: aspectId++, traits: Object.freeze(traits), schema }) as Aspect<T>;
+}
+
+export function hasAspect(world: World, entity: Entity, aspect: Aspect): boolean {
+    return aspect.traits.every((trait) => hasTrait(world, entity, trait));
+}
+
+export function getAspect(world: World, entity: Entity, aspect: Aspect): AspectRecord<Aspect> | undefined {
+    if (!hasAspect(world, entity, aspect)) return undefined;
+    return Object.assign({}, ...aspect.traits.map((trait) => getTrait(world, entity, trait)));
+}
+
+export function setAspect(world: World, entity: Entity, aspect: Aspect, value: Record<string, unknown>) {
+    for (const trait of aspect.traits) {
+        const fields = pickFields(trait, value);
+        if (Object.keys(fields).length) setTrait(world, entity, trait, fields);
+    }
+}
+
+export function addAspect(world: World, entity: Entity, aspect: Aspect, value: Record<string, unknown> = {}) {
+    for (const trait of aspect.traits) {
+        if (!hasTrait(world, entity, trait)) addTrait(world, entity, [trait, pickFields(trait, value)]);
+    }
+}
+
+export function removeAspect(world: World, entity: Entity, aspect: Aspect) {
+    removeTrait(world, entity, ...aspect.traits);
+}
+
+function pickFields(trait: Trait, value: Record<string, unknown>) {
+    const result: Record<string, unknown> = {};
+    for (const field of Object.keys(trait.schema)) if (field in value) result[field] = value[field];
+    return result;
+}
