+function subscribeAspect(
+    world: World,
+    aspect: Aspect,
+    type: 'add' | 'remove' | 'change',
+    callback: (entity: Entity) => void
+): QueryUnsubscriber {
+    const unsubscribers = aspect.traits.map((trait) => {
+        if (type === 'add') return world.onAdd(trait, (entity) => { if (hasAspect(world, entity, aspect)) callback(entity); });
+        if (type === 'remove') return world.onRemove(trait, (entity) => { if (hasAspect(world, entity, aspect)) callback(entity); });
+        return world.onChange(trait, (entity) => { if (hasAspect(world, entity, aspect)) callback(entity); });
+    });
+    return () => unsubscribers.forEach((unsubscribe) => unsubscribe());
+}
