+function createAspectQueryResult(
+    world: World,
+    entities: Entity[],
+    query: QueryInstance,
+    params: QueryParameter[]
+) {
+    const results = Object.assign(entities, {
+        readEach(callback: (state: any[], entity: Entity, index: number) => void) {
+            for (let i = 0; i < entities.length; i++) callback(readAspectState(world, entities[i], params), entities[i], i);
+            return results;
+        },
+        updateEach(callback: (state: any[], entity: Entity, index: number) => void) {
+            for (let i = 0; i < entities.length; i++) {
+                const entity = entities[i];
+                const state = readAspectState(world, entity, params);
+                callback(state, entity, i);
+                if (!world.has(entity)) continue;
+                writeAspectState(world, entity, params, state);
+            }
+            return results;
+        },
+        useStores(callback: any) { callback([], entities); return results; },
+        select(...selectParams: QueryParameter[]) { params = selectParams; return results; },
+        sort(callback: (a: Entity, b: Entity) => number = (a, b) => getEntityId(a) - getEntityId(b)) { Array.prototype.sort.call(entities, callback); return results; },
+    });
+    return results;
+}
+
+function readAspectState(world: World, entity: Entity, params: QueryParameter[]) {
+    const state: any[] = [];
+    for (const param of params) {
+        if (isAspect(param)) { state.push(getAspect(world, entity, param)); continue; }
+        if (isModifier(param)) {
+            if (param.type === 'not') continue;
+            for (const trait of param.traits) if (trait[$internal].type !== 'tag') state.push(trait[$internal].get(getEntityId(entity), getStore(world, trait)));
